WJ0008.example:
// Wrong:
let mut x = 5
let y = &x
let z = &mut x  // Error: already borrowed

// Correct:
let mut x = 5
let y = &x
// Use y first, then borrow mutably
let z = &mut x

WJ0009.example:
// Wrong:
let user = User {
    name: "Alice"
    // Missing 'age' field
}

// Correct:
let user = User {
    name: "Alice",
    age: 30
}

WJ0010.example:
// Wrong:
match value {
    Some(x) => println!("{}", x)
    // Missing None case
}

// Correct:
match value {
    Some(x) => println!("{}", x),
    None => println!("No value")
}
